// Validate input and guard against skipped/disabled cases.
const asset = $input.first().json;

if (asset._social_skip) {
  return [{ json: { _publish_skip: true, reason: asset.reason || 'Social publishing skipped' } }];
}

const required = ['topic_slug', 'date_key', 'asset_type', 'x', 'telegram', 'discord'];
for (const f of required) {
  if (!asset[f]) {
    throw new Error(`social_content_asset missing required field: ${f}`);
  }
}

return [{ json: { ...asset, _publish_skip: false } }];

// Expand asset into per-platform publish tasks.
// Each enabled platform produces one task.
const asset = $input.first().json;
const tasks = [];

if (asset.x && asset.x.enabled) {
  tasks.push({
    platform:       'x',
    post_type:      'post',
    post_text:      asset.x.post_text,
    thread:         asset.x.thread,
    topic_slug:     asset.topic_slug,
    date_key:       asset.date_key,
    publish_job_id: asset.publish_job_id
  });
}

if (asset.telegram && asset.telegram.enabled) {
  tasks.push({
    platform:       'telegram',
    post_type:      'digest',
    message_html:   asset.telegram.message_html,
    topic_slug:     asset.topic_slug,
    date_key:       asset.date_key,
    publish_job_id: asset.publish_job_id
  });
}

if (asset.discord && asset.discord.enabled) {
  tasks.push({
    platform:       'discord',
    post_type:      'embed',
    embed:          asset.discord.embed,
    topic_slug:     asset.topic_slug,
    date_key:       asset.date_key,
    publish_job_id: asset.publish_job_id
  });
}

if (tasks.length === 0) {
  return [{ json: { _publish_skip: true, reason: 'No publish tasks — all channels disabled' } }];
}

return tasks.map(t => ({ json: t }));

// Resolve the API endpoint and credentials for each platform task.
// Returns _api_skip: true (with a reason) instead of throwing when credentials
// are missing, so other platform tasks in the same execution can still proceed.

const task = $input.item.json;

function skipTask(reason) {
  console.log(`[Resolve API Endpoint] Skipping ${task.platform || 'unknown'} task: ${reason}`);
  return [{ json: { ...task, _api_skip: true, _api_skip_reason: reason } }];
}

if (task.platform === 'x') {
  const xBearerToken = $vars.SOCIAL_X_BEARER_TOKEN || null;
  if (!xBearerToken) {
    return skipTask('X publishing skipped: missing SOCIAL_X_BEARER_TOKEN in n8n Variables');
  }
  return [{ json: {
    ...task,
    _api_url:    'https://api.twitter.com/2/tweets',
    _api_method: 'POST',
    _api_headers: { 'Authorization': `Bearer ${xBearerToken}`, 'Content-Type': 'application/json' },
    _api_body:   { text: task.post_text }
  } }];
}

if (task.platform === 'telegram') {
  const botToken = $vars.SOCIAL_TELEGRAM_BOT_TOKEN || $vars.TELEGRAM_BOT_TOKEN || null;
  const chatId   = $vars.SOCIAL_TELEGRAM_CHAT_ID   || $vars.TELEGRAM_CHAT_ID   || null;
  if (!botToken || !chatId) {
    return skipTask('Telegram publishing skipped: missing SOCIAL_TELEGRAM_BOT_TOKEN and/or SOCIAL_TELEGRAM_CHAT_ID');
  }
  return [{ json: {
    ...task,
    _api_url:    `https://api.telegram.org/bot${botToken}/sendMessage`,
    _api_method: 'POST',
    _api_headers: { 'Content-Type': 'application/json' },
    _api_body:   { chat_id: chatId, text: task.message_html, parse_mode: 'HTML', disable_web_page_preview: false }
  } }];
}

if (task.platform === 'discord') {
  const webhookUrl = $vars.SOCIAL_DISCORD_WEBHOOK_URL || $vars.DISCORD_WEBHOOK_URL || null;
  if (!webhookUrl) {
    return skipTask('Discord publishing skipped: missing SOCIAL_DISCORD_WEBHOOK_URL');
  }
  return [{ json: {
    ...task,
    _api_url:    webhookUrl,
    _api_method: 'POST',
    _api_headers: { 'Content-Type': 'application/json' },
    _api_body:   { embeds: [task.embed] }
  } }];
}

return skipTask(`Unknown platform: ${task.platform}`);

// Handle API response and extract publish result.
// Each platform returns different response shapes.
const response = $input.item.json;
const task     = $('Resolve API Endpoint').item.json;

const statusCode = response._statusCode || response.statusCode || null;
const hasError = !!response.error || !!response.errors || (statusCode && statusCode >= 400);

if (hasError) {
  const errMsg = response.error
    ? (typeof response.error === 'string' ? response.error : JSON.stringify(response.error).slice(0, 300))
    : response.errors
      ? JSON.stringify(response.errors).slice(0, 300)
      : `HTTP ${statusCode} — ${JSON.stringify(response).slice(0, 300)}`;
  return [{ json: {
    platform:         task.platform,
    post_type:        task.post_type,
    topic_slug:       task.topic_slug,
    date_key:         task.date_key,
    status:           'failed',
    platform_post_id: null,
    error_message:    errMsg
  } }];
}

// Extract platform-specific post ID
let postId = null;
if (task.platform === 'x') {
  postId = response.data?.id || response.id || null;
} else if (task.platform === 'telegram') {
  postId = response.result?.message_id?.toString() || null;
} else if (task.platform === 'discord') {
  postId = response.id || null;
}

return [{ json: {
  platform:         task.platform,
  post_type:        task.post_type,
  topic_slug:       task.topic_slug,
  date_key:         task.date_key,
  status:           'published',
  platform_post_id: postId
} }];

// Write publish result to D1 social_publish_log.
const r = $input.item.json;
const attempt = Number.isFinite(Number(r.attempt)) ? Number(r.attempt) : 1;
return [{ json: {
  _d1_sql: `INSERT INTO social_publish_log
    (topic_slug, date_key, asset_type, source_type, platform, post_type,
     status, platform_post_id, error_message, attempt, created_at, updated_at)
  VALUES (?, ?, 'daily_post', 'daily_summary', ?, ?, ?, ?, ?, ?,
    strftime('%Y-%m-%dT%H:%M:%SZ','now'),
    strftime('%Y-%m-%dT%H:%M:%SZ','now')
  )`,
  _d1_params: [
    r.topic_slug,
    r.date_key,
    r.platform,
    r.post_type || 'post',
    r.status || 'published',
    r.platform_post_id || null,
    r.error_message || null,
    attempt
  ],
  ...r,
  attempt
} }];

// Log the skipped platform task so D1 can record it as 'skipped'.
const task = $input.item.json;
return [{ json: {
  platform:         task.platform,
  post_type:        task.post_type,
  topic_slug:       task.topic_slug,
  date_key:         task.date_key,
  status:           'skipped',
  platform_post_id: null,
  error_message:    task._api_skip_reason || 'Missing API credentials'
} }];
